// claim-office.spec.ts
import { describe, it, expect } from "vitest";

describe("MHPCO Claim Office", () => {
  // ===== Quote: empty and processing fee =====
  it.todo("empty item list yields premium of 5 G (processing fee only)");

  // ===== Quote: single item base premiums (no modifiers, follow-up contract to neutralize first-insurance) =====
  // Use a long-standing customer's follow-up contract OR show base via integration.
  // We start with the simplest: single-item premiums combining base + first-insurance for a newcomer with no history.
  it.todo("newcomer single sword (steel, enchantment 0, not cursed) yields premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("newcomer single amulet yields premium 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("newcomer single staff yields premium 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("newcomer single potion yields premium 49 G (40 base + 4 first-insurance + 5 fee)");
  it.todo("newcomer single rune yields premium 33 G (25 base + 3 first-insurance + 5 fee, rounded up)");

  // ===== Quote: component blocks =====
  it.todo("2 runes yield base premium 50 G (no block applies)");
  it.todo("3 runes yield base premium 60 G (block of 3 alike applies)");
  it.todo("4 runes yield base premium 100 G (block requires exactly 3)");
  it.todo("7 runes yield base premium 175 G (no block)");
  it.todo("2 runes + 1 moonstone yield base premium 75 G (different types, no block)");
  it.todo("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)");

  // ===== Quote: item-specific modifiers =====
  it.todo("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)");
  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge on item base");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");

  // ===== Quote: modifier scope on multi-item policies =====
  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");

  // ===== Quote: policy-wide modifiers =====
  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
  it.todo("follow-up contract gives 15% discount on policy base");

  // ===== Quote: rounding in MHPCO's favor =====
  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
  it.todo("intermediate amounts kept as fractions; only final premium is rounded");

  // ===== Quote: integration examples from spec =====
  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");

  // ===== Claim: basic deductible =====
  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");

  // ===== Claim: special clauses =====
  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");

  // ===== Claim: deductible per damage event (multi-item incident) =====
  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");

  // ===== Claim: rounding =====
  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");

  // ===== Claim: insurance sum and cap =====
  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");

  // ===== Claim: cap exhaustion across successive claims =====
  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");

  // ===== Claim: multiple items of same type =====
  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");

  // ===== CLI / scenario integration =====
  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");

  // ===== Error cases =====
  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
});

